    {"id": "api_pm_020", "question": "How would you organize a large Postman collection for maintainability across many endpoints and multiple testers?", "expected_answer": "Group requests into folders by resource/domain, use consistent naming conventions, centralize shared setup at the collection level, keep environments separate from the collection itself, and use version control (via Postman's Git integration or exported JSON) for collaborative review.", "difficulty": "Advanced", "category": "scenario"},
