def is_api_testing_selected(skills: List[str]) -> bool:
    """True when the candidate's skills indicate API testing is relevant -
    an explicit API/API Testing/Rest Assured/Postman skill, or Playwright
    (which commonly includes API testing in its scope)."""
    normalized = {s.strip().lower() for s in (skills or [])}
    triggers = {"api", "api testing", "rest assured", "restassured", "postman", "playwright"}
    return bool(normalized & triggers)


def get_api_testing_questions(count: int, skills: List[str]) -> List[Dict]:
    """
    Select `count` API testing questions, blending the core REST/testing
    fundamentals with tool-specific flavors (Rest Assured, Postman,
    Playwright API testing) based on which skills the candidate selected.
    """
    normalized = {s.strip().lower() for s in (skills or [])}
    has_java = "java" in normalized
    has_playwright = "playwright" in normalized
    has_postman = "postman" in normalized
    has_restassured = bool(normalized & {"rest assured", "restassured"})
    has_api_generic = bool(normalized & {"api", "api testing"})

    flavor_pools = []
    if has_restassured or (has_java and has_api_generic):
        flavor_pools.append(RESTASSURED_QUESTIONS)
    if has_postman:
        flavor_pools.append(POSTMAN_QUESTIONS)
    if has_playwright:
        flavor_pools.append(PLAYWRIGHT_API_QUESTIONS)

    # Blend: roughly half the reservation from core REST/architect-level
    # questions (always relevant regardless of tool), the rest split
    # across whichever tool-specific flavor(s) apply.
    core_target = max(1, count // 2)
    core_selected = random.sample(CORE_API_QUESTIONS, min(core_target, len(CORE_API_QUESTIONS)))

    remaining = max(0, count - len(core_selected))
    flavor_selected: List[Dict] = []
    if flavor_pools:
        per_flavor = max(1, remaining // len(flavor_pools))
        for pool in flavor_pools:
            flavor_selected.extend(random.sample(pool, min(per_flavor, len(pool))))
    else:
        # No specific tool flavor matched (e.g. just "API Testing" typed
        # generically) - fill the remainder from core questions instead.
        extra_needed = remaining
        already_ids = {q["id"] for q in core_selected}
        extra_pool = [q for q in CORE_API_QUESTIONS if q["id"] not in already_ids]
        flavor_selected.extend(random.sample(extra_pool, min(extra_needed, len(extra_pool))))

    combined = core_selected + flavor_selected
    random.shuffle(combined)
    combined = combined[:count]

    questions = []
    for q in combined:
        questions.append({
            "id": q["id"],
            "question": q["question"],
            "expected_answer": q["expected_answer"],
            "section": "API Testing",
            "difficulty": q["difficulty"],
            "category": q["category"],
        })
    return questions
